// HasResult applies the HasEdge predicate on the "result" edge.
func HasResult() predicate.BacktestTask {
	return predicate.BacktestTask(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2O, false, ResultTable, ResultColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasResultWith applies the HasEdge predicate on the "result" edge with a given conditions (other predicates).
func HasResultWith(preds ...predicate.BacktestResult) predicate.BacktestTask {
	return predicate.BacktestTask(func(s *sql.Selector) {
		step := newResultStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.BacktestTask) predicate.BacktestTask {
	return predicate.BacktestTask(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.BacktestTask) predicate.BacktestTask {
	return predicate.BacktestTask(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.BacktestTask) predicate.BacktestTask {
	return predicate.BacktestTask(sql.NotPredicates(p))
}
